import{_ as t,c as a,o,a5 as i,h4 as r,h5 as n,h6 as s,h7 as c}from"./chunks/framework.CVIjMMbU.js";const y=JSON.parse('{"title":"MiraclePlus","description":"","frontmatter":{"title":"MiraclePlus"},"headers":[],"relativePath":"news/qijichuangtan.md","filePath":"news/qijichuangtan.md","lastUpdated":1778655337000}'),l={name:"news/qijichuangtan.md"};function d(h,e,p,u,g,m){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="liii-stem-appears-at-the-miracleplus-demo-day-showcasing-its-potential-to-transform-research-tools-🚀" tabindex="-1">Liii STEM Appears at the MiraclePlus Demo Day, Showcasing Its Potential to Transform Research Tools 🚀 <a class="header-anchor" href="#liii-stem-appears-at-the-miracleplus-demo-day-showcasing-its-potential-to-transform-research-tools-🚀" aria-label="Permalink to “Liii STEM Appears at the MiraclePlus Demo Day, Showcasing Its Potential to Transform Research Tools 🚀”">​</a></h1><p>On <strong>June 8, 2025</strong>, MiraclePlus 2025 Spring Founder Camp Demo Day welcomed a new standout project: the core team behind <strong>Liii STEM (Liii STEM)</strong> took the stage and presented its vision and achievements in transforming research work to professional investors.</p><p>Founded by Dr. Qi Lu, former President and COO of Baidu, Corporate Vice President of Microsoft, and Executive Vice President of Yahoo, MiraclePlus is one of China&#39;s top startup accelerators focused on frontier technologies. Its distinctive &quot;invest first, then accelerate&quot; model is designed to address two core challenges for early-stage startups: &quot;product-market fit&quot; and &quot;sustainable survival,&quot; making it a highly sought-after fundraising platform for many early teams.</p><p>The development company behind Liii STEM, <strong>Liii Network</strong>, performed exceptionally well in the rigorous selection and evaluation process of the MiraclePlus founder camp, successfully ranking among the <strong>top 1.1%</strong> of teams and earning a valuable Demo Day spot.</p><hr><p>At the Demo Day, <strong>Shen Da, Founder, CEO, and CTO of Liii Network</strong>, addressed 1,000 professional investors and shared the inspiration behind Liii STEM, its technical highlights, and its market progress.</p><p>Shen Da said:</p><blockquote><p>&quot;Liii STEM has already integrated the core capabilities of Matlab and Mathematica. Our goal is to build the &#39;<strong>Cursor for research</strong>&#39; - not only for writing, but also for scientific computing and simulation, and ultimately to become the core entry point for scientific exploration.&quot;</p></blockquote><p>He revealed that the commercial version of Liii STEM launched paid closed beta testing in January 2025 and now covers <strong>32 universities worldwide</strong>. Even during the closed beta stage, it has already generated <strong>monthly revenue exceeding 10,000 yuan</strong>.</p><p><img src="'+r+'" alt="Photo of Shen Da giving the presentation"></p><p>At the project booth, <strong>Li Yansong, Co-founder and COO of Liii Network</strong>, continued giving hands-on software demonstrations to a steady stream of investors.</p><p>He emphasized:</p><blockquote><p>&quot;Liii STEM is our self-developed high-efficiency editing tool, a true &#39;<strong>must-have for research writing</strong>.&#39; It greatly simplifies the workflow and can multiply researchers&#39; paper-writing efficiency without requiring complex code. The product has now entered the market, attracting many researchers in physics and mathematics to purchase and use it.&quot;</p></blockquote><p><img src="'+n+'" alt="Dedicated Liii STEM booth"><br><img src="'+s+'" alt="Li Yansong demonstrating the product to investors"><br><img src="'+c+'" alt="Founder camp closing group photo"></p><hr><p>The Demo Day received an enthusiastic response. Related coverage of the Liii STEM project was highlighted in official posts by <a href="https://mp.weixin.qq.com/s/9WNx64CRkcyp0ezjkhtcJA" target="_blank" rel="noreferrer">MiraclePlus</a> and <a href="https://mp.weixin.qq.com/s/4n2qTgC8dpx_k5oZr89GTw" target="_blank" rel="noreferrer">Zhongguancun Innovation and Entrepreneurship</a>, drawing <strong>more than 10,000 views</strong> 🔥 and fully demonstrating the attention from the market and industry to its innovative value.</p>',16)])])}const v=t(l,[["render",d]]);export{y as __pageData,v as default};
